import json
import yaml


def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r') as f:
            data = yaml.safe_load(f)
        json_str = json.dumps(data)
        return json_str
    except FileNotFoundError:
        return f'Error: File not found: {yaml_file_path}'
    except yaml.YAMLError as e:
        return f'Error: Invalid YAML content: {str(e)}'
    except json.JSONEncodeError as e:
        return f'Error: JSON encoding failed: {str(e)}'
    except Exception as e:
        return f'Error: {str(e)}'

from typing import Dict
from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    query = (
        "//student[username/text() = $user and password/text() = $pass]"
    )
    students = root.xpath(query, user=username, pass=password)

    if not students:
        return None

    student = students[0]
    return {
        "name": student.find("name").text,
        "citizenship": student.find("citizenship").text,
        "age": student.find("age").text,
    }

