def checkAdminPassword(password):
    common_passwords = {'password', 'admin', '123456', 'letmein', 'qwerty', 'admin123', 'password1', 'guest', '000000', '123456789'}
    if password.lower() in common_passwords:
        return False
    if len(password) < 12:
        return False
    has_upper = has_lower = has_digit = has_special = False
    for c in password:
        if c.isupper():
            has_upper = True
        elif c.islower():
            has_lower = True
        elif c.isdigit():
            has_digit = True
        else:
            has_special = True
    return has_upper and has_lower and has_digit and has_special

