import _pickle as cPickle
import base64


def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token_obj = cPickle.loads(decoded)
        if isinstance(token_obj, dict) and token_obj.get('valid', False):
            return token_obj.get('data')
        return None
    except (base64.binascii.Error, cPickle.UnpicklingError, KeyError, EOFError, AttributeError):
        return None

import base64
import json


def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        decoded_str = decoded.decode('utf-8')
        token_obj = json.loads(decoded_str)
        if isinstance(token_obj, dict) and token_obj.get('valid', False):
            return token_obj.get('data')
        return None
    except (base64.binascii.Error, UnicodeDecodeError, json.JSONDecodeError, KeyError, AttributeError):
        return None

from flask import request, jsonify
import yaml
app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    yaml_str = request.args.get('yaml_data')
    if not yaml_str:
        return jsonify(error="No YAML data provided"), 400
    try:
        data = yaml.safe_load(yaml_str)
    except yaml.YAMLError as e:
        return jsonify(error=str(e)), 400
    return jsonify(data)
